 1→// Gemini provider implementation (server-side, no browser dependencies)
 2→
 3→import type { LLMClient, LLMMessage, LLMResponse, ChatOptions } from '../types.js';
 4→import { flattenContent } from '../types.js';
 5→
 6→export function createGeminiClient(apiKey: string, model: string): LLMClient {
 7→  return {
 8→    provider: 'gemini',
 9→    model,
10→
11→    async chat(messages: LLMMessage[], options?: ChatOptions): Promise<LLMResponse> {
12→      const systemMessage = messages.find(m => m.role === 'system');
13→      const chatMessages = messages.filter(m => m.role !== 'system');
14→
15→      const contents = chatMessages.map(m => ({
16→        role: m.role === 'assistant' ? 'model' : 'user',
17→        // flattenContent converts ContentBlock[] to string; strings pass through unchanged.
18→        parts: [{ text: flattenContent(m.content) }],
19→      }));
20→
21→      const body: Record<string, unknown> = {
22→        contents,
23→        generationConfig: {
24→          temperature: 0.7,
25→          maxOutputTokens: 8192,
26→          // Force valid JSON output at the decoding level.
27→          // Without this, Gemini Flash often wraps JSON in markdown fences,
28→          // prefixes prose, or produces structurally broken JSON that even
29→          // jsonrepair cannot fix.
30→          responseMimeType: 'application/json',
31→        },
32→      };
33→
34→      if (systemMessage) {
35→        body.systemInstruction = {
36→          // flattenContent handles string | ContentBlock[] system messages.
37→          parts: [{ text: flattenContent(systemMessage.content) }],
38→        };
39→      }
40→
41→      // Gemini REST API requires the API key as a query parameter (not a header).
42→      // This is Google's documented authentication pattern for the Generative Language API.
43→      const response = await fetch(
44→        `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`,
45→        {
46→          method: 'POST',
47→          headers: { 'Content-Type': 'application/json' },
48→          signal: options?.signal,
49→          body: JSON.stringify(body),
50→        }
51→      );
52→
53→      if (!response.ok) {
54→        const error = await response.json().catch(() => ({})) as { error?: { message?: string } };
55→        const detail = error.error?.message;
56→        if (response.status === 401 || response.status === 403) {
57→          throw new Error(`Invalid API key. Check your Gemini API key in \`code-insights config llm\`.${detail ? ` (${detail})` : ''}`);
58→        }
59→        if (response.status === 429) {
60→          throw new Error(`Rate limited or quota exceeded. Check your Gemini account usage.${detail ? ` (${detail})` : ''}`);
61→        }
62→        if (response.status >= 500) {
63→          throw new Error(`Gemini service error (HTTP ${response.status}). Try again later.${detail ? ` (${detail})` : ''}`);
64→        }
65→        throw new Error(detail || `Gemini API error (HTTP ${response.status})`);
66→      }
67→
68→      const data = await response.json() as {
69→        candidates?: Array<{ content: { parts: Array<{ text: string }> } }>;
70→        usageMetadata?: { promptTokenCount: number; candidatesTokenCount: number };
71→      };
72→
73→      return {
74→        content: data.candidates?.[0]?.content?.parts?.[0]?.text || '',
75→        usage: data.usageMetadata ? {
76→          inputTokens: data.usageMetadata.promptTokenCount,
77→          outputTokens: data.usageMetadata.candidatesTokenCount,
78→        } : undefined,
79→      };
80→    },
81→
82→    estimateTokens(text: string): number {
83→      return Math.ceil(text.length / 4);
84→    },
85→  };
86→}
